     1→/**
     2→ * Classification Pipeline Orchestrator
     3→ *
     4→ * Orchestrates the complete 9-stage classification pipeline with canonical signatures:
     5→ * (email, session, result, config) => void
     6→ *
     7→ * Pipeline Stages:
     8→ * 1. Hard Assertions - Domain-based high-confidence categorization
     9→ * 2. Strong Indicators - Weighted seed scoring with diminishing returns
    10→ * 3. Rule Scoring - Hierarchical pattern matching (high/medium/low tiers)
    11→ * 4. Attribute Detection - Cross-cutting signals (urgency, domains, structural patterns)
    12→ * 5. Attribute Influence - Role-based bonuses (CORE, PRIMARY_BOOST, etc.)
    13→ * 6. Disambiguation - Pairwise conflict resolution for close scores
    14→ * 7. Multi-label Selection - Confidence-based label assignment with co-presence rules
    15→ * 8. AI Routing - Selective AI classification for uncertain cases
    16→ * 9. Final Decision - Label assignment and action determination
    17→ * 10. Audit Trail - Complete explainability trace generation
    18→ */
    19→
    20→import { CategoryConfiguration } from '../types/category-configuration';
    21→import { logger } from '../utils/logger';
    22→import { ClassificationResult } from '../types/classification-result';
    23→import { ClassificationSession } from '../types/classification-session';
    24→import { EmailMessage } from '../types/email-message';
    25→
    26→// Validation utilities
    27→import { validateConfigInput, validateEmailInput } from '../utils/validation';
    28→
    29→// Domain lookup loader
    30→import { DomainLookup, loadDomainLookup } from '../config/domain-resolver';
    31→
    32→// Audit trail generator
    33→import { AuditTrailGenerator } from '../audit-trail/audit-trail-generator';
    34→
    35→// Initialization utilities
    36→import {
    37→  createClassificationResult,
    38→  createClassificationSession,
    39→  finalizeClassificationSession,
    40→  incrementSessionError,
    41→  incrementSessionSuccess,
    42→} from '../utils/initialization';
    43→
    44→// Pipeline stages (canonical signatures)
    45→import { actionDeterminationStage } from '../stages/action-determination';
    46→import { aiClassificationStage } from '../stages/ai-classification';
    47→import { aiFeatureExtractionStage } from '../stages/ai-feature-extraction';
    48→import { aiLabelFilteringStage } from '../stages/ai-label-filtering';
    49→import { aiRoutingStage } from '../stages/ai-routing';
    50→import { executeAttributeDetection } from '../stages/attribute-detection';
    51→import { executeAttributeInfluence } from '../stages/attribute-influence';
    52→import { executeDisambiguation } from '../stages/disambiguation';
    53→import { executeHardAssertions } from '../stages/hard-assertions';
    54→import { executeMultiLabelSelection } from '../stages/multi-label-selection';
    55→import { executeRuleScoring } from '../stages/rule-scoring';
    56→import { executeStrongIndicators } from '../stages/strong-indicators';
    57→// import { generateAuditTrail } from '../stages/audit-trail'; // TODO (T052): Wire audit trail after PipelineOutput/ClassificationResult architectural refactoring decision (see T052 re-evaluation criteria in tasks.md)
    58→
    59→// Stage-specific config types
    60→import type { ActionDeterminationConfig } from '../stages/action-determination';
    61→import type { AIClassificationConfig } from '../stages/ai-classification';
    62→import type { AIFeatureExtractionConfig } from '../stages/ai-feature-extraction';
    63→import type { AILabelFilteringConfig } from '../stages/ai-label-filtering';
    64→import type { AIRoutingConfig } from '../stages/ai-routing';
    65→import type { AttributeDetectionStageConfig } from '../stages/attribute-detection';
    66→import type { HardAssertionStageConfig } from '../stages/hard-assertions';
    67→import type { RuleScoringStageConfig } from '../stages/rule-scoring';
    68→import type { StrongIndicatorStageConfig } from '../stages/strong-indicators';
    69→import type { ConfidenceThresholds, MultiLabelConfig } from '../stages/types';
    70→// import type { AuditTrailConfig } from '../stages/audit-trail'; // TODO (T052): Wire audit trail config after PipelineOutput/ClassificationResult architectural refactoring decision (see T052 re-evaluation criteria in tasks.md)
    71→
    72→/**
    73→ * Pipeline stage execution order for replay functionality
    74→ */
    75→const STAGE_ORDER = [
    76→  'hard-assertions',
    77→  'strong-indicators',
    78→  'rule-scoring',
    79→  'attribute-detection',
    80→  'attribute-influence',
    81→  'disambiguation',
    82→  'multi-label-selection',
    83→  'ai-routing',
    84→  'ai-feature-extraction',
    85→  'ai-classification',
    86→  'ai-label-filtering',
    87→  'action-determination',
    88→] as const;
    89→
    90→/**
    91→ * Stage task interface for replay-from-stage support
    92→ *
    93→ * Wraps individual pipeline stage functions to enable selective execution
    94→ * based on replay parameters while maintaining minimal disruption to existing code.
    95→ */
    96→interface StageTask {
    97→  /**
    98→   * Stage identifier for replay functionality
    99→   */
   100→  name: string;
   101→
   102→  /**
   103→   * Execute the stage with canonical signature pattern
   104→   *
   105→   * @param email - Email message to process
   106→   * @param session - Classification session context
   107→   * @param result - Mutable classification result (modified in place)
   108→   * @param config - Stage-specific configuration
   109→   */
   110→  execute(
   111→    email: EmailMessage,
   112→    session: ClassificationSession,
   113→    result: ClassificationResult,
   114→    config: CategoryConfiguration
   115→  ): Promise<void>;
   116→
   117→  /**
   118→   * Determine if this stage should be skipped for replay functionality
   119→   *
   120→   * @param replayFromStage - Optional stage to start replay from
   121→   * @returns true if stage should be skipped, false to execute
   122→   */
   123→  shouldSkip(replayFromStage?: string): boolean;
   124→}
   125→
   126→/**
   127→ * Error result for batch processing when individual email fails
   128→ */
   129→export interface ClassificationErrorResult {
   130→  error: Error;
   131→  emailId: string;
   132→  processingDurationMs: number;
   133→}
   134→
   135→/**
   136→ * Classification Pipeline orchestrator
   137→ *
   138→ * Manages sequential execution of classification stages with proper context
   139→ * propagation, error handling, and performance tracking.
   140→ */
   141→export class ClassificationPipeline {
   142→  private readonly config: CategoryConfiguration;
   143→  private readonly testMode: boolean;
   144→  private readonly domainLookup: DomainLookup;
   145→  private readonly auditTrail: AuditTrailGenerator;
   146→
   147→  /**
   148→   * Initialize classification pipeline with validated configuration
   149→   *
   150→   * @param config - Complete category configuration including processingConfig
   151→   * @param testMode - If true, use timestamp-based session IDs for easier debugging
   152→   * @throws {Error} If configuration validation fails
   153→   */
   154→  constructor(config: CategoryConfiguration, testMode: boolean = false) {
   155→    // Validate processing configuration exists
   156→    validateConfigInput(config.processingConfig);
   157→
   158→    // Check for deprecated/invalid config properties (defensive runtime validation)
   159→    const processingConfigAny = config.processingConfig as Record<string, unknown>;
   160→    if ('confidenceThresholds' in processingConfigAny) {
   161→      throw new Error(
   162→        'Configuration validation failed: confidenceThresholds is deprecated (use settings.multiLabelSelection instead)'
   163→      );
   164→    }
   165→
   166→    // Validate required config properties are present (defensive runtime validation)
   167→    if (!config.processingConfig.settings) {
   168→      throw new Error('Configuration validation failed: settings is required');
   169→    }
   170→    if (!config.processingConfig.settings.multiLabelSelection) {
   171→      throw new Error('Configuration validation failed: settings.multiLabelSelection is required');
   172→    }
   173→
   174→    // Validate multi-label selection thresholds
   175→    const multiLabelSettings = config.processingConfig.settings.multiLabelSelection;
   176→    if (
   177→      !multiLabelSettings ||
   178→      multiLabelSettings.highConfidenceThreshold < 0 ||
   179→      multiLabelSettings.mediumConfidenceThreshold < 0 ||
   180→      multiLabelSettings.lowConfidenceThreshold < 0 ||
   181→      multiLabelSettings.secondaryLabelMinGap < 0
   182→    ) {
   183→      throw new Error('Invalid multi-label selection thresholds: all values must be non-negative');
   184→    }
   185→
   186→    this.config = config;
   187→    this.testMode = testMode;
   188→
   189→    // Load domain lookup from config/domain-sources.json
   190→    // Gracefully handles missing/malformed files by returning empty lookup
   191→    this.domainLookup = loadDomainLookup();
   192→
   193→    // Initialize audit trail generator for progressive recording
   194→    this.auditTrail = new AuditTrailGenerator(config);
   195→  }
   196→
   197→  /**
   198→   * Get configuration (for testing and future stage integration)
   199→   */
   200→  getConfig(): CategoryConfiguration {
   201→    return this.config;
   202→  }
   203→
   204→  /**
   205→   * Helper function to determine if a stage should be skipped for replay
   206→   *
   207→   * @param stageName - Name of the current stage
   208→   * @param replayFromStage - Stage to start replay from (optional)
   209→   * @returns true if stage should be skipped, false to execute
   210→   */
   211→  private shouldSkipStage(stageName: string, replayFromStage?: string): boolean {
   212→    if (!replayFromStage) return false;
   213→    const replayIndex = STAGE_ORDER.indexOf(replayFromStage as (typeof STAGE_ORDER)[number]);
   214→    const currentIndex = STAGE_ORDER.indexOf(stageName as (typeof STAGE_ORDER)[number]);
   215→    return replayIndex !== -1 && currentIndex < replayIndex;
   216→  }
   217→
   218→  /**
   219→   * Stage configuration mapping for factory pattern
   220→   */
   221→  private readonly stageConfigs = {
   222→    'hard-assertions': () => this.getHardAssertionConfig(),
   223→    'strong-indicators': () => this.getStrongIndicatorConfig(),
   224→    'rule-scoring': () => this.getRuleScoringConfig(),
   225→    'attribute-detection': () => this.getAttributeDetectionConfig(),
   226→    'attribute-influence': () => this.config,
   227→    disambiguation: () => this.config,
   228→    'multi-label-selection': () => ({
   229→      multiLabel: this.getMultiLabelConfig(),
   230→      confidenceThresholds: this.getConfidenceThresholds(),
   231→    }),
   232→    'ai-routing': () => this.getAIRoutingConfig(),
   233→    'ai-feature-extraction': () => this.getAIFeatureExtractionConfig(),
   234→    'ai-classification': () => this.getAIClassificationConfig(),
   235→    'ai-label-filtering': () => this.getAILabelFilteringConfig(),
   236→    'action-determination': () => this.getActionDeterminationConfig(),
   237→  } as const;
   238→
   239→  /**
   240→   * Stage function mapping for factory pattern
   241→   */
   242→  private readonly stageFunctions = {
   243→    'hard-assertions': executeHardAssertions,
   244→    'strong-indicators': executeStrongIndicators,
   245→    'rule-scoring': executeRuleScoring,
   246→    'attribute-detection': executeAttributeDetection,
   247→    'attribute-influence': executeAttributeInfluence,
   248→    disambiguation: executeDisambiguation,
   249→    'multi-label-selection': (
   250→      email: EmailMessage,
   251→      session: ClassificationSession,
   252→      result: ClassificationResult,
   253→      config: { multiLabel: MultiLabelConfig; confidenceThresholds: ConfidenceThresholds }
   254→    ) => {
   255→      executeMultiLabelSelection(email, session, result, config.multiLabel, config.confidenceThresholds);
   256→    },
   257→    'ai-routing': aiRoutingStage,
   258→    'ai-feature-extraction': aiFeatureExtractionStage,
   259→    'ai-classification': aiClassificationStage,
   260→    'ai-label-filtering': aiLabelFilteringStage,
   261→    'action-determination': actionDeterminationStage,
   262→  } as const;
   263→
   264→  /**
   265→   * Conditional execution for AI stages
   266→   */
   267→  private readonly conditionalStages = new Set(['ai-feature-extraction', 'ai-classification', 'ai-label-filtering']);
   268→
   269→  /**
   270→   * Create a single stage task using factory pattern
   271→   */
   272→  private createStageTask(stageName: keyof typeof this.stageConfigs): StageTask {
   273→    return {
   274→      name: stageName,
   275→      execute: async (email, session, result, _config) => {
   276→        // Check if this is a conditional AI stage
   277→        if (this.conditionalStages.has(stageName) && !result.needsAiClassification) {
   278→          return;
   279→        }
   280→
   281→        const stageConfig = this.stageConfigs[stageName]();
   282→        const stageFunction = this.stageFunctions[stageName];
   283→        await stageFunction(email, session, result, stageConfig as never);
   284→      },
   285→      shouldSkip: (replayFromStage) => this.shouldSkipStage(stageName, replayFromStage),
   286→    };
   287→  }
   288→
   289→  /**
   290→   * Create ordered array of stage tasks using factory pattern
   291→   *
   292→   * Each stage task wraps existing stage functions with replay logic
   293→   * while preserving canonical signatures and conditional execution.
   294→   *
   295→   * @returns Array of stage tasks in execution order
   296→   */
   297→  private createStageTasks(): StageTask[] {
   298→    return STAGE_ORDER.map((stageName) => this.createStageTask(stageName));
   299→  }
   300→
   301→  /**
   302→   * Map stage task names (kebab-case) to StageName (camelCase)
   303→   */
   304→  private mapToStageName(taskName: string): import('../types/stage-name').StageName | null {
   305→    const mapping: Record<string, import('../types/stage-name').StageName> = {
   306→      'hard-assertions': 'hardAssertions',
   307→      'strong-indicators': 'strongIndicators',
   308→      'rule-scoring': 'ruleScoring',
   309→      'attribute-detection': 'attributeDetection',
   310→      'attribute-influence': 'attributeInfluence',
   311→      disambiguation: 'disambiguation',
   312→      'multi-label-selection': 'multiLabelSelection',
   313→      'ai-routing': 'aiPipeline',
   314→      'ai-feature-extraction': 'aiPipeline',
   315→      'ai-classification': 'aiPipeline',
   316→      'ai-label-filtering': 'aiPipeline',
   317→      'action-determination': 'actionDetermination',
   318→    };
   319→    return mapping[taskName] || null;
   320→  }
   321→
   322→  /**
   323→   * Core pipeline execution logic shared by both classify methods
   324→   */
   325→  private async executePipelineStages(
   326→    email: EmailMessage,
   327→    session: ClassificationSession,
   328→    result: ClassificationResult,
   329→    pipelineStartTime: number,
   330→    replayFromStage?: string
   331→  ): Promise<void> {
   332→    // Get stage tasks array
   333→    const stageTasks = this.createStageTasks();
   334→
   335→    // Execute stages using StageTask architecture
   336→    for (const stageTask of stageTasks) {
   337→      // Check if this stage should be skipped for replay
   338→      if (stageTask.shouldSkip(replayFromStage)) {
   339→        if (this.testMode && replayFromStage) {
   340→          logger.debug({ stage: stageTask.name, replayFrom: replayFromStage }, 'Skipping stage');
   341→        }
   342→        continue;
   343→      }
   344→
   345→      // Log stage execution only in test mode
   346→      if (this.testMode) {
   347→        logger.debug({ stage: stageTask.name }, 'Executing stage');
   348→      }
   349→
   350→      // Execute the stage with unified error handling
   351→      try {
   352→        await stageTask.execute(email, session, result, this.config);
   353→
   354→        // Record stage result in audit trail (progressive recording)
   355→        // Map AI sub-stages to single 'aiPipeline' stage name
   356→        const stageName = this.mapToStageName(stageTask.name);
   357→        if (stageName) {
   358→          // Only record once for AI pipeline (after ai-label-filtering completes)
   359→          if (stageName === 'aiPipeline' && stageTask.name !== 'ai-label-filtering') {
   360→            // Skip recording for intermediate AI stages
   361→            continue;
   362→          }
   363→          this.auditTrail.recordStage(stageName, result, session);
   364→        }
   365→      } catch (error) {
   366→        // Record partial trace before throwing
   367→        this.auditTrail.recordFailure(result, session, error instanceof Error ? error : new Error(String(error)));
   368→        throw new Error(`Stage '${stageTask.name}' failed: ${error instanceof Error ? error.message : String(error)}`);
   369→      }
   370→    }
   371→
   372→    // All stages completed successfully - finalize audit trail
   373→    this.auditTrail.finalize(result, session);
   374→  }
   375→
   376→  /**
   377→   * Unified error handling for pipeline failures
   378→   */
   379→  private createPipelineError(email: EmailMessage, startTime: number, error: unknown): Error {
   380→    const endTime = Date.now();
   381→    const message = error instanceof Error ? error.message : String(error);
   382→    return new Error(`Classification pipeline failed for email ${email.id} after ${endTime - startTime}ms: ${message}`);
   383→  }
   384→
   385→  /**
   386→   * Execute classification pipeline using StageTask architecture with optional replay support
   387→   *
   388→   * Provides the foundation for true replay-from-stage functionality by iterating
   389→   * through stage tasks and selectively skipping stages based on replay parameters.
   390→   *
   391→   * @param email - Email message to classify
   392→   * @param replayFromStage - Optional stage name to start replay from
   393→   * @returns Complete classification result with selected labels
   394→   * @throws {Error} If email validation fails or any stage throws unrecoverable error
   395→   */
   396→  async classifyWithStageTask(email: EmailMessage, replayFromStage?: string): Promise<ClassificationResult> {
   397→    const pipelineStartTime = Date.now();
   398→
   399→    try {
   400→      // Validate email input
   401→      validateEmailInput(email);
   402→
   403→      // Create classification session for single email
   404→      const session = createClassificationSession(this.config.processingConfig, 'sequential', 1, this.testMode);
   405→
   406→      // Create classification result
   407→      const result = createClassificationResult(email.id, session.id, 0);
   408→
   409→      // Execute pipeline stages using shared logic
   410→      await this.executePipelineStages(email, session, result, pipelineStartTime, replayFromStage);
   411→
   412→      // Mark session as successful
   413→      incrementSessionSuccess(session);
   414→      finalizeClassificationSession(session);
   415→
   416→      // Update final processing time
   417→      result.processingDurationMs = Date.now() - pipelineStartTime;
   418→      result.processedAt = new Date();
   419→
   420→      return result;
   421→    } catch (error) {
   422→      throw this.createPipelineError(email, pipelineStartTime, error);
   423→    }
   424→  }
   425→
   426→  /**
   427→   * Execute classification pipeline using provided session (for batch processing)
   428→   *
   429→   * Uses an externally-created session to enable multiple emails to share the same
   430→   * sessionId. This is essential for batch processing where all emails should be
   431→   * grouped under one session for traceability.
   432→   *
   433→   * @param email - Email message to classify
   434→   * @param session - Existing classification session to use
   435→   * @param batchPosition - Position of email in batch (for result metadata)
   436→   * @param replayFromStage - Optional stage name to start replay from
   437→   * @returns Complete classification result with selected labels
   438→   * @throws {Error} If email validation fails or any stage throws unrecoverable error
   439→   */
   440→  async classifyWithSession(
   441→    email: EmailMessage,
   442→    session: ClassificationSession,
   443→    batchPosition: number = 0,
   444→    replayFromStage?: string
   445→  ): Promise<ClassificationResult> {
   446→    const pipelineStartTime = Date.now();
   447→
   448→    try {
   449→      // Validate email input
   450→      validateEmailInput(email);
   451→
   452→      // Create classification result using provided session
   453→      const result = createClassificationResult(email.id, session.id, batchPosition);
   454→
   455→      // Execute pipeline stages using shared logic
   456→      await this.executePipelineStages(email, session, result, pipelineStartTime, replayFromStage);
   457→
   458→      // Update final processing time
   459→      result.processingDurationMs = Date.now() - pipelineStartTime;
   460→      result.processedAt = new Date();
   461→
   462→      return result;
   463→    } catch (error) {
   464→      throw this.createPipelineError(email, pipelineStartTime, error);
   465→    }
   466→  }
   467→
   468→  /**
   469→   * Shared configuration composition helpers
   470→   */
   471→  private getBaseStageConfig() {
   472→    return {
   473→      // Type assertion: CategorySignals structure is compatible with stage-specific signal configs
   474→      categorySignals: this.config.processingConfig.categorySignals as Record<string, never>,
   475→      domainLookup: this.domainLookup,
   476→    };
   477→  }
   478→
   479→  private getOpenAIConfig(requiredFor: string) {
   480→    const openaiApiKey = process.env.OPENAI_API_KEY || '';
   481→    if (!openaiApiKey) {
   482→      throw new Error(`OPENAI_API_KEY environment variable is required for ${requiredFor}`);
   483→    }
   484→    return {
