   529→      settings: this.config.processingConfig.settings.ruleScoring,
   530→      tuningParameters: {
   531→        // Map config values (KHigh, KMedium, KLow) to internal names
   532→        // These are multipliers applied to sum of ALL tier weights (not topK limits)
   533→        KHigh: tuningParams?.KHigh ?? 1,
   534→        KMedium: tuningParams?.KMedium ?? 0.7,
   535→        KLow: tuningParams?.KLow ?? 0.3,
   536→        // TAIL_DAMPEN and TAIL_RATIO_CAP control score aggregation behavior
   537→        // Use conservative defaults if not specified in config
   538→        TAIL_DAMPEN: 0.5,
   539→        TAIL_RATIO_CAP: 0.25,
   540→        aggregationCap: tuningParams?.aggregationCap ?? 1.0,
   541→      },
   542→    };
   543→  }
   544→
   545→  /**
   546→   * Extract configuration for attribute detection stage
