   614→
   615→  /**
   616→   * Extract configuration for AI classification stage
   617→   */
   618→  private getAIClassificationConfig(): AIClassificationConfig {
   619→    return {
   620→      openai: this.getOpenAIConfig('AI classification'),
   621→      prompts: this.config.processingConfig.aiPrompts.finalClassification,
   622→      classificationSchema: {
   623→        name: 'email_classification',
   624→        description: 'Classify email into categories',
   625→        schema: {
   626→          type: 'object',
   627→          properties: {
   628→            primaryCategory: { type: 'string' },
   629→            secondaryCategories: { type: 'array', items: { type: 'string' } },
   630→            confidence: { type: 'number' },
   631→            reasoning: { type: 'string' },
   632→          },
   633→          required: ['primaryCategory', 'secondaryCategories', 'confidence', 'reasoning'],
   634→          additionalProperties: false,
   635→        },
   636→        strict: true,
   637→      },
   638→      skipConditions: {
