   640→        skipReasons: this.config.processingConfig.settings.aiRouting.skipAiConditions,
   641→      },
   642→      retryPolicy: this.getRetryPolicy(),
   643→    };
   644→  }
   645→
   646→  /**
   647→   * Extract configuration for AI label filtering stage
   648→   */
   649→  private getAILabelFilteringConfig(): AILabelFilteringConfig {
   650→    const settings = this.config.processingConfig.settings.multiLabelSelection;
   651→    return {
   652→      labelAssignmentRules: {
   653→        maxLabels: settings.maxLabels,
   654→        minSecondaryConfidence: settings.mediumConfidenceThreshold,
   655→        allowedCombinations: settings.allowedCombinations.map((combo) => combo.categories.join('+')),
   656→      },
   657→    };
   658→  }
   659→
   660→  /**
   661→   * Extract configuration for action determination stage
   662→   */
   663→  private getActionDeterminationConfig(): ActionDeterminationConfig {
   664→    return {
   665→      archiveThresholds: {
   666→        lowImportance: 0.3,
   667→        mediumImportance: 0.5,
   668→        highImportance: 0.7,
   669→      },
   670→      defaultArchiveThreshold: 'mediumImportance',
   671→      actionSettings: {
   672→        archiveIfBelowThreshold: true,
   673→        markAsReadIfArchived: false,
   674→        applyCustomActions: false,
   675→      },
   676→    };
   677→  }
   678→
   679→  /**
   680→   * Execute classification pipeline on single email
   681→   *
   682→   * Uses the StageTask architecture for consistent pipeline execution.
   683→   * This method now delegates to classifyWithStageTask for unified pipeline logic.
   684→   *
   685→   * @param email - Email message to classify
   686→   * @returns Complete classification result with selected labels
   687→   * @throws {Error} If email validation fails or any stage throws unrecoverable error
   688→   */
   689→  async classify(email: EmailMessage): Promise<ClassificationResult> {
   690→    // Delegate to StageTask architecture (no replay, execute all stages)
   691→    return this.classifyWithStageTask(email);
   692→  }
   693→
   694→  /**
   695→   * Process multiple emails sequentially with shared session context
   696→   *
   697→   * Uses the StageTask architecture for consistent pipeline execution.
   698→   * Each email is processed independently using classifyWithStageTask.
   699→   *
   700→   * @param emails - Array of email messages to classify
   701→   * @returns Array of classification results or error results
   702→   */
   703→  async classifyBatch(emails: EmailMessage[]): Promise<Array<ClassificationResult | ClassificationErrorResult>> {
   704→    const results: Array<ClassificationResult | ClassificationErrorResult> = [];
   705→
   706→    // Create batch session for tracking
   707→    const session = createClassificationSession(
   708→      this.config.processingConfig,
   709→      'sequential',
   710→      emails.length,
   711→      this.testMode
   712→    );
   713→
   714→    for (let i = 0; i < emails.length; i++) {
   715→      const email = emails[i];
   716→      const startTime = Date.now();
   717→      try {
   718→        // Use StageTask architecture for consistent pipeline execution
   719→        const result = await this.classifyWithStageTask(email);
   720→
   721→        // Update batch position and session tracking
   722→        result.batchPosition = i;
   723→        result.sessionId = session.id;
   724→        incrementSessionSuccess(session);
   725→
   726→        results.push(result);
   727→      } catch (error) {
   728→        // Continue processing batch on individual email error
   729→        incrementSessionError(session, email.id, 'pipeline', error instanceof Error ? error.message : String(error));
   730→        results.push({
   731→          error: error instanceof Error ? error : new Error(String(error)),
   732→          emailId: email.id,
   733→          processingDurationMs: Date.now() - startTime,
   734→        });
   735→      }
   736→    }
   737→
   738→    // Finalize session after all emails processed
   739→    finalizeClassificationSession(session);
   740→
   741→    return results;
   742→  }
