/**
 * Mock OpenAI client for integration tests
 *
 * Provides deterministic, valid responses for AI stages without external API calls.
 * Used to eliminate flakiness from non-deterministic AI responses and async timing issues.
 *
 * Usage in test files:
 * ```typescript
 * jest.mock('openai');
 * import { OpenAI } from 'openai';
 * ```
 */

/**
 * Mock feature extraction response
 * Matches FeatureExtractionData interface from ai-feature-extraction stage
 */
const mockFeatureExtractionResponse = {
  categoryEnhancements: [
    {
      category: 'bills_receipts',
      confidenceBoost: 0.15,
      reasoning: 'Mock: Invoice-like content detected',
    },
    {
      category: 'shopping_commerce',
      confidenceBoost: 0.05,
      reasoning: 'Mock: Commercial transaction detected',
    },
  ],
  extractedFeatures: {
    semanticIntent: 'transactional',
    topicClassification: 'financial',
    urgencyLevel: 'normal',
    contentType: 'business',
  },
  processingNotes: ['Mock AI feature extraction for testing'],
};

/**
 * Mock classification response
 * Matches FinalClassification interface from ai-classification stage
 */
const mockClassificationResponse = {
  primaryCategory: 'bills_receipts',
  secondaryCategories: ['shopping_commerce'],
  confidence: 0.85,
  reasoning: 'Mock AI classification: Invoice detected with high confidence based on transactional content',
  categoryScores: {
    bills_receipts: 0.85,
    shopping_commerce: 0.65,
    personal: 0.20,
  },
};

/**
 * Mock OpenAI API response structure
 * Matches the response format expected by ai-feature-extraction and ai-classification stages
 */
export const createMockOpenAIResponse = (content: Record<string, unknown>) => ({
  choices: [
    {
      message: {
        content: JSON.stringify(content),
        role: 'assistant',
      },
      finish_reason: 'stop',
      index: 0,
    },
  ],
  usage: {
    total_tokens: 150,
    prompt_tokens: 100,
    completion_tokens: 50,
  },
  model: 'gpt-4o-mini',
  id: 'mock-completion-id',
  object: 'chat.completion',
  created: Date.now(),
});

/**
 * Mock OpenAI chat completions API
 *
 * Intelligently returns feature extraction or classification response
 * based on the prompt content.
 */
const mockCreate = jest.fn().mockImplementation(async (params: { messages: Array<{ role: string; content: string }> }) => {
  // Determine which response to return based on prompt content
  const userMessage = params.messages.find((m) => m.role === 'user')?.content || '';

  // If prompt mentions "feature extraction" or "semantic features", return feature extraction response
  if (
    userMessage.includes('feature') ||
    userMessage.includes('semantic') ||
    userMessage.includes('extract') ||
    userMessage.includes('enhancement')
  ) {
    return createMockOpenAIResponse(mockFeatureExtractionResponse);
  }

  // Otherwise, return classification response
  return createMockOpenAIResponse(mockClassificationResponse);
});

/**
 * Mock OpenAI client class
 */
export class OpenAI {
  chat = {
    completions: {
      create: mockCreate,
    },
  };

  constructor(_config?: { apiKey?: string }) {
    // Mock constructor - no-op
  }
}

/**
 * Export mock functions for test assertions and customization
 */
export const mockOpenAICreate = mockCreate;

/**
 * Reset mock to default responses (use in beforeEach/afterEach)
 */
export const resetOpenAIMock = () => {
  mockCreate.mockClear();
};

/**
 * Customize mock response for specific test cases
 *
 * @example
 * ```typescript
 * setMockOpenAIResponse({
 *   primaryCategory: 'personal',
 *   secondaryCategories: [],
 *   confidence: 0.95,
 *   reasoning: 'Custom test case'
 * });
 * ```
 */
export const setMockOpenAIResponse = (response: Record<string, unknown>) => {
  mockCreate.mockResolvedValueOnce(createMockOpenAIResponse(response));
};

/**
 * Make mock throw error for testing error handling
 */
export const setMockOpenAIError = (error: Error) => {
  mockCreate.mockRejectedValueOnce(error);
};

