    orchestrator = new ClassificationOrchestrator(validMinimalCategoryConfig);
  });

  describe('Single Email Classification Integration (FR-002, FR-004)', () => {
    test('should execute real classification pipeline and preserve results', async () => {
      // Setup: Realistic email
      const email = createDetailedEmail(
        'msg-001',
        'Your Amazon order #123456789 has shipped',
        'shipment-tracking@amazon.com'
      );

      // Execute: Real classification pipeline through orchestrator (may fail due to AI)
      try {
        const result = await orchestrator.classify(email);

        // Validate: FR-002 - Classification engine preserves sophisticated pipeline
        expect(result.selectedLabels).toBeDefined();
        expect(Array.isArray(result.selectedLabels)).toBe(true);

        // Validate: Result structure from real pipeline
        expect(result.candidateScores).toBeDefined();
        expect(typeof result.candidateScores).toBe('object');

        expect(result.selectionSummary).toBeDefined();
        expect(result.selectionSummary.totalLabels).toBeGreaterThanOrEqual(0);
        expect(result.selectionSummary.primaryCategory).toBeDefined();

        // Validate: FR-005 - Performance metrics preserved
        expect(result.processingDurationMs).toBeGreaterThan(0);

        // Validate: FR-004 - Explainability traces preserved
        if ('explainabilityTrace' in result) {
          expect(result.explainabilityTrace).toBeDefined();
        }
      } catch (error) {
        // AI classification may fail without proper setup - validate error context
        expect((error as Error).message).toContain('msg-001');
      }
    });

    test('should handle emails with minimal data through real pipeline', async () => {
      // Setup: Edge case - minimal email data
      const email = createMinimalEmail('msg-minimal');

      // Execute: Should complete without throwing (or handle AI errors gracefully)
      try {
        const result = await orchestrator.classify(email);

        // Validate: Pipeline handles edge case gracefully
        expect(result).toBeDefined();
        expect(result.selectedLabels).toBeDefined();
        expect(result.processingDurationMs).toBeGreaterThan(0);
      } catch (error) {
        // Minimal email may trigger AI classification that fails - validate error context
