        expect(result.processingDurationMs).toBeGreaterThan(0);

        // Validate: Duration is realistic (within actual wall clock time + overhead)
        expect(result.processingDurationMs).toBeLessThanOrEqual(actualDuration + 100); // 100ms tolerance
      } catch (error) {
        // AI classification may fail - that's acceptable
        expect((error as Error).message).toContain('msg-perf');
      }
    });

    test('should preserve individual processing durations in batch', async () => {
      // Setup
      const emails = Array.from({ length: 3 }, (_, i) =>
        createDetailedEmail(`msg-${i}`, `Subject ${i}`, 'sender@example.com')
      );

      // Execute
      const results = await orchestrator.classifyBatch(emails);

      // Validate: Each result has duration
      results.forEach((result) => {
        if (!('error' in result)) {
