**Key Insight**: No signature changes required! The `aiClient` flows through existing config objects.

#### 4. Stage Refactoring (AI Stages)

**File**: `packages/classification-engine/src/stages/ai-feature-extraction.ts`

```typescript
import { AIClient } from '../ai/ai-client';  // ← New import

export interface AIFeatureExtractionConfig {
  openai: {
    apiKey: string;
    model: string;
    temperature: number;
    responseFormat: 'json_schema' | 'json_object';
    client: AIClient;  // ← Add client to config interface
  };
  prompts: { /* ... */ };
  featureExtractionSchema: { /* ... */ };
  retryPolicy: { /* ... */ };
}

export async function aiFeatureExtractionStage(
  email: EmailMessage,
  session: ClassificationSession,
  result: ClassificationResult,
  config: AIFeatureExtractionConfig
): Promise<void> {
  // ... validation logic ...

  // BEFORE: Direct OpenAI import
  // const openai = new OpenAI({ apiKey: config.openai.apiKey });

  // AFTER: Use injected client
  const client = config.openai.client;

  while (retryCount < config.retryPolicy.maxRetries) {
    try {
      // BEFORE: openai.chat.completions.create(...)
      // AFTER: Use abstraction
      const response = await client.chatComplete({
        model: config.openai.model,
        temperature: config.openai.temperature,
        messages: [
          { role: 'system', content: systemPrompt },
          { role: 'user', content: userPrompt },
        ],
        response_format: responseFormat,
      });

      // ... rest of logic unchanged ...
    } catch (error) {
      // ... retry logic ...
    }
  }
}
```

