### Example 1: Simple Test with Injected Mock

```typescript
test('should classify email with injected mock AI', async () => {
  // Arrange
  const mockAI = new MockAIClient();
  const pipeline = new ClassificationPipeline(config, true, mockAI);
  const orchestrator = new ClassificationOrchestrator(config, pipeline);
  const email = createTestEmail('Invoice from Stripe');

  // Act
  const result = await orchestrator.classify(email);

  // Assert
  expect(result.selectedLabels).toContain('bills_receipts');
  expect(mockAI.getCallCount()).toBeGreaterThan(0);
});
```

### Example 2: Testing AI Skip Logic

```typescript
test('should skip AI for high-confidence emails', async () => {
  const mockAI = new MockAIClient();
  const pipeline = new ClassificationPipeline(config, true, mockAI);

  // Email with hard assertion (100% confidence)
  const email = createTestEmail('Receipt from store@amazon.com');

  const result = await pipeline.classify(email);

  // AI should NOT be called for high-confidence emails
  expect(mockAI.getCallCount()).toBe(0);
  expect(result.selectedLabels).toContain('bills_receipts');
});
```

